<script>
    document.addEventListener('DOMContentLoaded', function() {
        var buttons = document.querySelectorAll('.metadata-button');
        var metadataItems = document.querySelectorAll('.metadata-item');
        var descriptionDisplay = document.getElementById('description-display');

        // Handle category button clicks
        buttons.forEach(function(button) {
            button.addEventListener('click', function() {
                var index = button.getAttribute('data-index');

                // Remove active state from all buttons
                buttons.forEach(function(btn) {
                    btn.classList.remove('bg-[#679740]');
                    btn.classList.add('bg-[#1c7671]');
                });

                // Add active state to clicked button
                button.classList.remove('bg-[#1c7671]');
                button.classList.add('bg-[#679740]');

                // Hide all metadata items
                metadataItems.forEach(function(item) {
                    item.classList.add('hidden');
                });

                // Show selected metadata item
                var selectedItem = document.querySelector('[data-metadata-index="' + index + '"]');
                if (selectedItem) {
                    selectedItem.classList.remove('hidden');
                }

                // Clear description
                descriptionDisplay.innerHTML = '<p class="text-center text-[#1c7671]/50 italic">Selecciona un nombre para ver su descripción</p>';
            });
        });

        // Handle name item clicks
        document.addEventListener('click', function(e) {
            var nameItem = e.target.closest('.name-item');
            if (nameItem) {
                // Remove active state from all name items
                document.querySelectorAll('.name-item').forEach(function(item) {
                    item.classList.remove('active');
                });

                // Add active state to clicked name
                nameItem.classList.add('active');

                // Show description
                var description = nameItem.getAttribute('data-description');
                descriptionDisplay.innerHTML = '<p>' + description + '</p>';
            }
        });

        // Handle global data button clicks
        var globalButtons = document.querySelectorAll('.global-button');
        var globalDataItems = document.querySelectorAll('.global-data-item');

        globalButtons.forEach(function(button) {
            button.addEventListener('click', function() {
                var index = button.getAttribute('data-global-index');

                // Remove active state from all global buttons
                globalButtons.forEach(function(btn) {
                    btn.classList.remove('bg-[#679740]');
                    btn.classList.add('bg-[#1c7671]');
                });

                // Add active state to clicked button
                button.classList.remove('bg-[#1c7671]');
                button.classList.add('bg-[#679740]');

                // Hide all global data items
                globalDataItems.forEach(function(item) {
                    item.classList.add('hidden');
                });

                // Show selected global data item
                var selectedGlobalItem = document.querySelector('[data-global-display-index="' + index + '"]');
                if (selectedGlobalItem) {
                    selectedGlobalItem.classList.remove('hidden');
                }
            });
        });
    });
</script>

